INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (159, '7dc36fa41b13', 'e6c479b7b3b94ad5', '科技', '33', 'In Japan, the robot isn’t coming for your job; it’s filling the one nobody wants', 'TechCrunch', '2026-04-05 14:00:00+00', 'https://techcrunch.com/2026/04/05/japan-is-proving-experimental-physical-ai-is-ready-for-the-real-world/', '["https://techcrunch.com/wp-content/uploads/2022/09/GettyImages-965917342.jpg?resize=1200,779", "https://techcrunch.com/wp-content/uploads/2024/09/tc-lockup.svg", "https://techcrunch.com/wp-content/uploads/2024/09/tc-logo-mobile.svg", "https://techcrunch.com/wp-content/uploads/2022/09/GettyImages-965917342.jpg?w=1024", "https://techcrunch.com/wp-content/uploads/2021/08/IMG_3905.jpeg?w=150"]', NULL, NULL, false, '{"summary_en": "Driven by labor shortages, Japan is pushing physical AI from pilot projects into real-world deployment."}', '2026-04-06 08:35:34.60371+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (160, '7dc36fa41b13', 'e6c479b7b3b94ad5', '科技', '33', 'I let Gemini in Google Maps plan my day and it went surprisingly well', 'The Verge', '2026-04-05 14:00:00+00', 'https://www.theverge.com/tech/907015/gemini-google-maps-hands-on', '["https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/IMG_0562.jpg?quality=90&strip=all&crop=0%2C15.095986038394%2C100%2C69.808027923211&w=1200", "https://www.google-analytics.com/g/collect?v=2&tid=G-C3QZPB4GVE&cid=555&en=noscript_page_view", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195790/ALLISON_JOHNSON.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/IMG_0562.jpg?quality=90&strip=all&crop=12.5%2C0%2C75%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195790/ALLISON_JOHNSON.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=96"]', NULL, NULL, false, '{"summary_en": "You may be familiar with Gemini as the thing that''s in every Google service you use - whether you want it or not. While it''s been a constant, sometimes unwelcome presence in Gmail for at least the past year, it''s a relatively new addition to Maps. And you know what? It''s kind of great. To […]"}', '2026-04-06 08:35:34.60371+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (161, '7dc36fa41b13', 'e6c479b7b3b94ad5', '科技', '33', 'Is the Slate Truck too minimal for its own good?', 'The Verge', '2026-04-05 13:00:00+00', 'https://www.theverge.com/transportation/905947/slate-truck-ev-minimal-range-size-interior-design', '["https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/Slate-Truck-5.png?quality=90&strip=all&crop=0%2C10.806933475316%2C100%2C78.386133049368&w=1200", "https://www.google-analytics.com/g/collect?v=2&tid=G-C3QZPB4GVE&cid=555&en=noscript_page_view", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195793/ANDREW_HAWKINS.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/Slate-Truck-5.png?quality=90&strip=all&crop=16.603773584906%2C0%2C66.792452830189%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195793/ANDREW_HAWKINS.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=96"]', NULL, NULL, false, '{"summary_en": "The first thing you notice about the Slate Truck is its size. It''s small, surprisingly so. In a country where trucks often come with their own zip code, Slate''s pickup is refreshingly puny, measuring 174.6 inches long, 70.6 inches wide, and 69.3 inches tall, with a curb weight of approximately 3,602 pounds (1,634kg). As a […]"}', '2026-04-06 08:35:34.60371+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (162, '7dc36fa41b13', 'e6c479b7b3b94ad5', '科技', '33', 'How the Amazon Echo learned to talk — and listen', 'The Verge', '2026-04-05 12:24:45+00', 'https://www.theverge.com/podcast/907146/amazon-echo-alexa-version-history', '["https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/VRG_VRH_ECHO_Site.png?quality=90&strip=all&crop=0%2C10.732984293194%2C100%2C78.534031413613&w=1200", "https://www.google-analytics.com/g/collect?v=2&tid=G-C3QZPB4GVE&cid=555&en=noscript_page_view", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195807/DAVID_PIERCE.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195807/DAVID_PIERCE.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=96", "https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/VRG_VST_0402_Site.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400"]', NULL, NULL, false, '{"summary_en": "Jeff Bezos badly wanted a voice computer. He had been saying so publicly since the very early days of Amazon, telling anyone who would listen about why voice might make it easier and more natural to interact with technology. (And to buy stuff from Jeff Bezos.) But when a team at Amazon set out to […]"}', '2026-04-06 08:35:34.60371+00');
