INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (164, '7dc36fa41b13', 'e6c479b7b3b94ad5', '科技', '33', 'CBP facility codes sure seem to have leaked via online flashcards', 'Ars Technica - All content', '2026-04-05 11:07:27+00', 'https://arstechnica.com/security/2026/04/cbp-facility-codes-sure-seem-to-have-leaked-via-online-flashcards/', '["https://cdn.arstechnica.net/wp-content/uploads/2018/08/GettyImages-925067740-1152x648.jpg", "https://cdn.arstechnica.net/wp-content/uploads/2018/08/GettyImages-925067740-300x200.jpg", "https://cdn.arstechnica.net/wp-content/uploads/2023/09/wired-headshot.jpg", "https://cdn.arstechnica.net/wp-content/themes/ars-v9/public/images/firework-loader.75ab30.gif", "https://cdn.arstechnica.net/wp-content/uploads/2026/04/GettyImages-520147094-768x432.jpg"]', NULL, NULL, false, '{"summary_en": "Quizlet flashcards seem to include sensitive information about gate security at CBP locations."}', '2026-04-06 08:35:34.60371+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (165, '7dc36fa41b13', '1e965f57bc764808', '体育娱乐', 'xhs', 'Ranveer Singh’s ‘Dhurandhar: The Revenge’ Crosses $174 Million Globally, Becomes First Indian Film to Top $25 Million in North America', 'Variety', '2026-04-06 08:05:15+00', 'https://variety.com/2026/film/box-office/ranveer-singh-dhurandhar-the-revenge-174-million-globally-1236709179/', '["https://variety.com/wp-content/uploads/2026/03/Dhurandhar-The-Revenge.jpg?crop=0px%2C25px%2C1000px%2C562px&resize=1000%2C563", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/03/Dhurandhar-The-Revenge.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "Jio Studios and B62 Studios’ “Dhurandhar: The Revenge” has crossed INR1,622 crores ($174.4 million) worldwide through its third weekend, becoming the first Indian film to surpass $25 million in North America and €1 million ($1.1 million) in Germany. The Aditya Dhar-directed spy-action sequel’s India gross stands at $132.1 million. In Germany, the film established itself […]"}', '2026-04-06 08:35:37.07112+00');
