INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (190, 'cb7fff031c0f', '6ce5965054474142', '体育娱乐', 'xhs', '‘Star Wars: Maul — Shadow Lord’ Is an Uneven but Promising Extension of the ‘Clone Wars’ Saga: TV Review', 'Variety', '2026-04-06 07:01:00+00', 'https://variety.com/2026/tv/reviews/star-wars-maul-shadow-lord-review-clone-wars-1236706487/', '["https://variety.com/wp-content/uploads/2026/04/MAUL_Trailer1_Still_16.jpg?w=1000&h=563&crop=1", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/04/MAUL_Trailer1_Still_16.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "Next month, the “Star Wars” franchise will return to theaters after an astonishing seven-year absence with Jon Favreau’s “The Mandalorian and Grogu,” a feature spinoff of the director’s hit Disney+ series “The Mandalorian.” The premiere is a confirmation of what was already clear to fans: that since 2019 — the year both “The Mandalorian” and “The […]"}', '2026-04-06 08:49:29.792884+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (191, 'cb7fff031c0f', '6ce5965054474142', '体育娱乐', 'xhs', '‘Faces of Death’ Review: A ’70s-Style B-Horror Movie Taps into the Growing Appetite for Horror That’s ‘Real’', 'Variety', '2026-04-06 03:30:11+00', 'https://variety.com/2026/film/reviews/faces-of-death-review-1236706326/', '["https://variety.com/wp-content/uploads/2026/04/FACES-OF-DEATH-Still-7.jpg?w=1000&h=563&crop=1", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/04/FACES-OF-DEATH-Still-7.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "The idea that a sicko like Arthur isn’t just a serial killer — he’s part of the new anything-goes attention economy! — is a provocative but facile idea. Yet that’s part of what gives \"Faces of Death\" the texture of a ''70s grindhouse movie. They often had ideas too. \"Faces of Death\" is \"ambitious\" trash, with the courage of its own gaudy thematic grandiloquence."}', '2026-04-06 08:49:29.792884+00');
