INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (226, 'cb7fff031c0f', 'e90e002a932b4fa8', '体育娱乐', 'xhs', 'Korea Box Office: ‘Project Hail Mary’ Ascends to No. 1 Dethroning ‘The King’s Warden’', 'Variety', '2026-04-06 07:44:10+00', 'https://variety.com/2026/film/box-office/korea-box-office-project-hail-mary-no-1-the-kings-warden-1236709170/', '["https://variety.com/wp-content/uploads/2026/03/PHM_36568_R2.jpg?crop=0px%2C185px%2C4496px%2C2531px&resize=1000%2C563", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/03/PHM_36568_R2.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "“Project Hail Mary” rose to the top position at the South Korean box office during the weekend of Apr. 3–05, 2026. According to data from KOBIS, the tracking service operated by the Korean Film Council, the film earned $2.4 million from 328,750 admissions, capturing a 39.56% revenue share. Since its Mar. 18 debut, the film, […]"}', '2026-04-06 08:49:36.382189+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (227, 'cb7fff031c0f', 'e90e002a932b4fa8', '体育娱乐', 'xhs', 'China Box Office: ‘The Super Mario Galaxy Movie’ Launches to Top Spot', 'Variety', '2026-04-06 07:04:35+00', 'https://variety.com/2026/film/box-office/china-box-office-the-super-mario-galaxy-movie-1236709168/', '["https://variety.com/wp-content/uploads/2026/04/MCDSUMA_UV092.jpg?crop=404px%2C0px%2C2236px%2C1257px&resize=1000%2C563", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/04/MCDSUMA_UV092.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "Universal’s “The Super Mario Galaxy Movie” blasted into first place at the China box office during the April 3–5 weekend, according to data from Artisan Gateway, earning RMB57.1 million ($8.3 million) in its debut frame. China Film’s drama “It’s OK,” after debuting in fifth place with previews last week, opened on April 3 and climbed […]"}', '2026-04-06 08:49:36.382189+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (228, 'cb7fff031c0f', 'e90e002a932b4fa8', '体育娱乐', 'xhs', '‘Star Wars: Maul — Shadow Lord’ Is an Uneven but Promising Extension of the ‘Clone Wars’ Saga: TV Review', 'Variety', '2026-04-06 07:01:00+00', 'https://variety.com/2026/tv/reviews/star-wars-maul-shadow-lord-review-clone-wars-1236706487/', '["https://variety.com/wp-content/uploads/2026/04/MAUL_Trailer1_Still_16.jpg?w=1000&h=563&crop=1", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/04/MAUL_Trailer1_Still_16.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "Next month, the “Star Wars” franchise will return to theaters after an astonishing seven-year absence with Jon Favreau’s “The Mandalorian and Grogu,” a feature spinoff of the director’s hit Disney+ series “The Mandalorian.” The premiere is a confirmation of what was already clear to fans: that since 2019 — the year both “The Mandalorian” and “The […]"}', '2026-04-06 08:49:36.382189+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (392, '2c8e82d46332', '3bda1ce234ce4010', '政治经济', '33', 'Iran War Live Updates: Israel and Iran Trade Attacks After Trump’s New Hormuz Ultimatum', 'NYT > World News', '2026-04-06 08:57:32+00', 'https://www.nytimes.com/live/2026/04/06/world/iran-war-trump-israel', '[]', NULL, NULL, false, '{"summary_en": "The fighting on Monday morning followed President Trump’s threat to bomb power plants and bridges on Tuesday if Iran did not open the Strait of Hormuz."}', '2026-04-06 09:09:22.840085+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (229, 'cb7fff031c0f', 'e90e002a932b4fa8', '体育娱乐', 'xhs', '‘Faces of Death’ Review: A ’70s-Style B-Horror Movie Taps into the Growing Appetite for Horror That’s ‘Real’', 'Variety', '2026-04-06 03:30:11+00', 'https://variety.com/2026/film/reviews/faces-of-death-review-1236706326/', '["https://variety.com/wp-content/uploads/2026/04/FACES-OF-DEATH-Still-7.jpg?w=1000&h=563&crop=1", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/04/FACES-OF-DEATH-Still-7.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "The idea that a sicko like Arthur isn’t just a serial killer — he’s part of the new anything-goes attention economy! — is a provocative but facile idea. Yet that’s part of what gives \"Faces of Death\" the texture of a ''70s grindhouse movie. They often had ideas too. \"Faces of Death\" is \"ambitious\" trash, with the courage of its own gaudy thematic grandiloquence."}', '2026-04-06 08:49:36.382189+00');
