INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (307, '04b8d4019b72', '6757f34b36e34252', '科技', '33', 'In Japan, the robot isn’t coming for your job; it’s filling the one nobody wants', 'TechCrunch', '2026-04-05 14:00:00+00', 'https://techcrunch.com/2026/04/05/japan-is-proving-experimental-physical-ai-is-ready-for-the-real-world/', '["https://techcrunch.com/wp-content/uploads/2022/09/GettyImages-965917342.jpg?resize=1200,779", "https://techcrunch.com/wp-content/uploads/2024/09/tc-lockup.svg", "https://techcrunch.com/wp-content/uploads/2024/09/tc-logo-mobile.svg", "https://techcrunch.com/wp-content/uploads/2022/09/GettyImages-965917342.jpg?w=1024", "https://techcrunch.com/wp-content/uploads/2021/08/IMG_3905.jpeg?w=150"]', NULL, NULL, false, '{"summary_en": "Driven by labor shortages, Japan is pushing physical AI from pilot projects into real-world deployment."}', '2026-04-06 08:53:47.346285+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (308, '04b8d4019b72', '6757f34b36e34252', '科技', '33', 'I let Gemini in Google Maps plan my day and it went surprisingly well', 'The Verge', '2026-04-05 14:00:00+00', 'https://www.theverge.com/tech/907015/gemini-google-maps-hands-on', '["https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/IMG_0562.jpg?quality=90&strip=all&crop=0%2C15.095986038394%2C100%2C69.808027923211&w=1200", "https://www.google-analytics.com/g/collect?v=2&tid=G-C3QZPB4GVE&cid=555&en=noscript_page_view", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195790/ALLISON_JOHNSON.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/IMG_0562.jpg?quality=90&strip=all&crop=12.5%2C0%2C75%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195790/ALLISON_JOHNSON.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=96"]', NULL, NULL, false, '{"summary_en": "You may be familiar with Gemini as the thing that''s in every Google service you use - whether you want it or not. While it''s been a constant, sometimes unwelcome presence in Gmail for at least the past year, it''s a relatively new addition to Maps. And you know what? It''s kind of great. To […]"}', '2026-04-06 08:53:47.346285+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (309, '04b8d4019b72', '6757f34b36e34252', '科技', '33', 'Is the Slate Truck too minimal for its own good?', 'The Verge', '2026-04-05 13:00:00+00', 'https://www.theverge.com/transportation/905947/slate-truck-ev-minimal-range-size-interior-design', '["https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/Slate-Truck-5.png?quality=90&strip=all&crop=0%2C10.806933475316%2C100%2C78.386133049368&w=1200", "https://www.google-analytics.com/g/collect?v=2&tid=G-C3QZPB4GVE&cid=555&en=noscript_page_view", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195793/ANDREW_HAWKINS.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/Slate-Truck-5.png?quality=90&strip=all&crop=16.603773584906%2C0%2C66.792452830189%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195793/ANDREW_HAWKINS.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=96"]', NULL, NULL, false, '{"summary_en": "The first thing you notice about the Slate Truck is its size. It''s small, surprisingly so. In a country where trucks often come with their own zip code, Slate''s pickup is refreshingly puny, measuring 174.6 inches long, 70.6 inches wide, and 69.3 inches tall, with a curb weight of approximately 3,602 pounds (1,634kg). As a […]"}', '2026-04-06 08:53:47.346285+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (310, '04b8d4019b72', '6757f34b36e34252', '科技', '33', 'How the Amazon Echo learned to talk — and listen', 'The Verge', '2026-04-05 12:24:45+00', 'https://www.theverge.com/podcast/907146/amazon-echo-alexa-version-history', '["https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/VRG_VRH_ECHO_Site.png?quality=90&strip=all&crop=0%2C10.732984293194%2C100%2C78.534031413613&w=1200", "https://www.google-analytics.com/g/collect?v=2&tid=G-C3QZPB4GVE&cid=555&en=noscript_page_view", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195807/DAVID_PIERCE.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/chorus/author_profile_images/195807/DAVID_PIERCE.0.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=96", "https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/VRG_VST_0402_Site.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400"]', NULL, NULL, false, '{"summary_en": "Jeff Bezos badly wanted a voice computer. He had been saying so publicly since the very early days of Amazon, telling anyone who would listen about why voice might make it easier and more natural to interact with technology. (And to buy stuff from Jeff Bezos.) But when a team at Amazon set out to […]"}', '2026-04-06 08:53:47.346285+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (311, '04b8d4019b72', '6757f34b36e34252', '科技', '33', 'Grammarly’s sloppelganger saga', 'The Verge', '2026-04-05 12:00:00+00', 'https://www.theverge.com/column/906606/grammarly-expert-review-ai-saga', '["https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/268400_Grammarlys_sloppelganger_saga_CVirginia.jpg?quality=90&strip=all&crop=0%2C10.732984293194%2C100%2C78.534031413613&w=1200", "https://www.google-analytics.com/g/collect?v=2&tid=G-C3QZPB4GVE&cid=555&en=noscript_page_view", "https://platform.theverge.com/wp-content/uploads/sites/2/2025/10/STEVIE_BONIFIELD_BLURPLE.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/2026/04/268400_Grammarlys_sloppelganger_saga_CVirginia.jpg?quality=90&strip=all&crop=16.666666666667%2C0%2C66.666666666667%2C100&w=2400", "https://platform.theverge.com/wp-content/uploads/sites/2/2025/10/STEVIE_BONIFIELD_BLURPLE.jpg?quality=90&strip=all&crop=0%2C0%2C100%2C100&w=96"]', NULL, NULL, false, '{"summary_en": "This is The Stepback, a weekly newsletter breaking down one essential story from the tech world. For more on the ups and downs of AI, follow Stevie Bonifield. The Stepback arrives in our subscribers'' inboxes at 8AM ET. Opt in for The Stepback here. How it started Most people probably know Grammarly for its browser […]"}', '2026-04-06 08:53:47.346285+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (312, '04b8d4019b72', '6757f34b36e34252', '科技', '33', 'CBP facility codes sure seem to have leaked via online flashcards', 'Ars Technica - All content', '2026-04-05 11:07:27+00', 'https://arstechnica.com/security/2026/04/cbp-facility-codes-sure-seem-to-have-leaked-via-online-flashcards/', '["https://cdn.arstechnica.net/wp-content/uploads/2018/08/GettyImages-925067740-1152x648.jpg", "https://cdn.arstechnica.net/wp-content/uploads/2018/08/GettyImages-925067740-300x200.jpg", "https://cdn.arstechnica.net/wp-content/uploads/2023/09/wired-headshot.jpg", "https://cdn.arstechnica.net/wp-content/themes/ars-v9/public/images/firework-loader.75ab30.gif", "https://cdn.arstechnica.net/wp-content/uploads/2026/04/GettyImages-520147094-768x432.jpg"]', NULL, NULL, false, '{"summary_en": "Quizlet flashcards seem to include sensitive information about gate security at CBP locations."}', '2026-04-06 08:53:47.346285+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (313, '04b8d4019b72', '168e765c5b0f4965', '体育娱乐', 'xhs', 'Ranveer Singh’s ‘Dhurandhar: The Revenge’ Crosses $174 Million Globally, Becomes First Indian Film to Top $25 Million in North America', 'Variety', '2026-04-06 08:05:15+00', 'https://variety.com/2026/film/box-office/ranveer-singh-dhurandhar-the-revenge-174-million-globally-1236709179/', '["https://variety.com/wp-content/uploads/2026/03/Dhurandhar-The-Revenge.jpg?crop=0px%2C25px%2C1000px%2C562px&resize=1000%2C563", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/03/Dhurandhar-The-Revenge.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "Jio Studios and B62 Studios’ “Dhurandhar: The Revenge” has crossed INR1,622 crores ($174.4 million) worldwide through its third weekend, becoming the first Indian film to surpass $25 million in North America and €1 million ($1.1 million) in Germany. The Aditya Dhar-directed spy-action sequel’s India gross stands at $132.1 million. In Germany, the film established itself […]"}', '2026-04-06 08:53:50.993958+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (314, '04b8d4019b72', '168e765c5b0f4965', '体育娱乐', 'xhs', 'Korea Box Office: ‘Project Hail Mary’ Ascends to No. 1 Dethroning ‘The King’s Warden’', 'Variety', '2026-04-06 07:44:10+00', 'https://variety.com/2026/film/box-office/korea-box-office-project-hail-mary-no-1-the-kings-warden-1236709170/', '["https://variety.com/wp-content/uploads/2026/03/PHM_36568_R2.jpg?crop=0px%2C185px%2C4496px%2C2531px&resize=1000%2C563", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/03/PHM_36568_R2.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "“Project Hail Mary” rose to the top position at the South Korean box office during the weekend of Apr. 3–05, 2026. According to data from KOBIS, the tracking service operated by the Korean Film Council, the film earned $2.4 million from 328,750 admissions, capturing a 39.56% revenue share. Since its Mar. 18 debut, the film, […]"}', '2026-04-06 08:53:50.993958+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (315, '04b8d4019b72', '168e765c5b0f4965', '体育娱乐', 'xhs', 'China Box Office: ‘The Super Mario Galaxy Movie’ Launches to Top Spot', 'Variety', '2026-04-06 07:04:35+00', 'https://variety.com/2026/film/box-office/china-box-office-the-super-mario-galaxy-movie-1236709168/', '["https://variety.com/wp-content/uploads/2026/04/MCDSUMA_UV092.jpg?crop=404px%2C0px%2C2236px%2C1257px&resize=1000%2C563", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/04/MCDSUMA_UV092.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "Universal’s “The Super Mario Galaxy Movie” blasted into first place at the China box office during the April 3–5 weekend, according to data from Artisan Gateway, earning RMB57.1 million ($8.3 million) in its debut frame. China Film’s drama “It’s OK,” after debuting in fifth place with previews last week, opened on April 3 and climbed […]"}', '2026-04-06 08:53:50.993958+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (316, '04b8d4019b72', '168e765c5b0f4965', '体育娱乐', 'xhs', '‘Star Wars: Maul — Shadow Lord’ Is an Uneven but Promising Extension of the ‘Clone Wars’ Saga: TV Review', 'Variety', '2026-04-06 07:01:00+00', 'https://variety.com/2026/tv/reviews/star-wars-maul-shadow-lord-review-clone-wars-1236706487/', '["https://variety.com/wp-content/uploads/2026/04/MAUL_Trailer1_Still_16.jpg?w=1000&h=563&crop=1", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/04/MAUL_Trailer1_Still_16.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "Next month, the “Star Wars” franchise will return to theaters after an astonishing seven-year absence with Jon Favreau’s “The Mandalorian and Grogu,” a feature spinoff of the director’s hit Disney+ series “The Mandalorian.” The premiere is a confirmation of what was already clear to fans: that since 2019 — the year both “The Mandalorian” and “The […]"}', '2026-04-06 08:53:50.993958+00');
INSERT INTO public.materials (id, run_id, task_id, section, source_agent, title, source_media, published_at, link, images, summary_zh, brief_zh, is_primary_candidate, metadata, created_at) VALUES (317, '04b8d4019b72', '168e765c5b0f4965', '体育娱乐', 'xhs', '‘Faces of Death’ Review: A ’70s-Style B-Horror Movie Taps into the Growing Appetite for Horror That’s ‘Real’', 'Variety', '2026-04-06 03:30:11+00', 'https://variety.com/2026/film/reviews/faces-of-death-review-1236706326/', '["https://variety.com/wp-content/uploads/2026/04/FACES-OF-DEATH-Still-7.jpg?w=1000&h=563&crop=1", "https://sb.scorecardresearch.com/p?c1=2&c2=6035310&c4=&cv=3.9&cj=1", "https://variety.com/wp-content/uploads/2026/04/FACES-OF-DEATH-Still-7.jpg?w=1000&h=667&crop=1", "https://variety.com/wp-content/themes/pmc-variety-2020/assets/public/lazyload-fallback.gif", "https://pixel.quantserve.com/pixel?a.1=&a.2=p-31f3D02tYU8zY"]', NULL, NULL, false, '{"summary_en": "The idea that a sicko like Arthur isn’t just a serial killer — he’s part of the new anything-goes attention economy! — is a provocative but facile idea. Yet that’s part of what gives \"Faces of Death\" the texture of a ''70s grindhouse movie. They often had ideas too. \"Faces of Death\" is \"ambitious\" trash, with the courage of its own gaudy thematic grandiloquence."}', '2026-04-06 08:53:50.993958+00');
